import json
import requests
from urllib.parse import urlparse

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']

    enrich_url_header = 'x-enrich-url'
    if enrich_url_header in headers:
        enrich_urls = headers[enrich_url_header][0]['value'].split(',')
        enriched_data = {}

        for url in enrich_urls:
            parsed_url = urlparse(url)
            if parsed_url.scheme and parsed_url.netloc:
                try:
                    response = requests.get(url, timeout=5)
                    response.raise_for_status()
                    enriched_data[url] = response.json()  # Assuming JSON response
                except (requests.RequestException, ValueError) as e:
                    enriched_data[url] = str(e)

        request['headers']['x-enriched-data'] = [{'key': 'X-Enriched-Data', 'value': json.dumps(enriched_data), 'overwrite': True}]

    return {
        'status': 200,
        'body': request['body'],
        'headers': request['headers']
    }